import { useState, useEffect } from 'react';

interface HabitDay {
  date: string;
  water: number;
  stretch: number;
  laundry: boolean;
  bedMade: boolean;
  vacuum: number;
  breakfast: boolean;
  lunch: boolean;
  dinner: boolean;
}

const HABITS_KEY = 'habits_data';

function today(): string {
  return new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
}

function isToday(dateStr: string): boolean {
  const d = new Date(dateStr);
  const t = new Date();
  return d.toDateString() === t.toDateString();
}

const emptyDay = (): HabitDay => ({
  date: today(),
  water: 0,
  stretch: 0,
  laundry: false,
  bedMade: false,
  vacuum: 0,
  breakfast: false,
  lunch: false,
  dinner: false,
});

export function HabitsWidget() {
  const [data, setData] = useState<HabitDay[]>([]);
  const [showHistory, setShowHistory] = useState(false);

  useEffect(() => {
    fetch('/api/habits')
      .then(r => r.json())
      .then(serverData => {
        if (serverData && Array.isArray(serverData)) {
          setData(serverData);
        }
      })
      .catch(() => {
        const saved = localStorage.getItem(HABITS_KEY);
        if (saved) setData(JSON.parse(saved));
      });
  }, []);

  const sync = (newData: HabitDay[]) => {
    setData(newData);
    localStorage.setItem(HABITS_KEY, JSON.stringify(newData));
    fetch('/api/habits', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(newData),
    }).catch(() => {});
  };

  const todayData = (): HabitDay => {
    const existing = data.find(d => isToday(d.date));
    if (existing) return existing;
    return emptyDay();
  };

  const t = todayData();

  const update = (field: keyof HabitDay, value: boolean | number) => {
    const updated = { ...t, [field]: value };
    const rest = data.filter(d => !isToday(d.date));
    sync([updated, ...rest]);
  };

